import { useState } from 'react';
import { COLLEGES, computePrediction } from '../data';

const EXAMS = ['JEE Main', 'JEE Advanced', 'BITSAT', 'VITEEE', 'MHT-CET', 'KCET', 'WBJEE'];
const CATS  = ['General', 'OBC', 'SC', 'ST', 'EWS'];
const BRANCHES = ['Computer Science (CSE)', 'Information Technology (IT)', 'Electronics (ECE)', 'Mechanical Engineering', 'Civil Engineering', 'Chemical Engineering'];
const STATES = ['Delhi', 'Maharashtra', 'Rajasthan', 'Uttar Pradesh', 'Karnataka', 'Tamil Nadu', 'West Bengal', 'Gujarat'];
const EXTRAS = ['None', 'Sports (State Level)', 'Cultural Activities', 'NSS / NCC', 'Olympiad Winner', 'Published Research'];

const ML_MODELS = [
  { key: 'lr',  label: 'Linear Regression',  color: '#00e5b4', desc: 'Fits a linear relationship between inputs and admission probability.' },
  { key: 'rf',  label: 'Random Forest',       color: '#6c63ff', desc: 'Ensemble of decision trees for robust non-linear prediction.' },
  { key: 'log', label: 'Logistic Regression', color: '#ffb830', desc: 'Classifies admission as probable/improbable with a probability score.' },
];

export default function AdmissionPredictor() {
  const [form, setForm] = useState({ p10: 92, p12: 88, cgpa: 8.4, entrance: 145, exam: 'JEE Main', category: 'General', branch: 'Computer Science (CSE)', state: 'Delhi', extra: 'Sports (State Level)' });
  const [result, setResult] = useState(null);
  const [loading, setLoading] = useState(false);

  const set = (k, v) => setForm(f => ({ ...f, [k]: v }));

  const runPrediction = async () => {
    setLoading(true);
    await new Promise(r => setTimeout(r, 1200));
    const res = computePrediction({ p10: +form.p10, p12: +form.p12, cgpa: +form.cgpa, entrance: +form.entrance, category: form.category, extra: form.extra });
    setResult(res);
    setLoading(false);
  };

  const eligible = result ? COLLEGES.filter(c => c.match <= result.overall + 12) : [];

  return (
    <div className="page-wrapper animate-in">
      <div className="page-header">
        <div className="page-header-left">
          <h1 className="page-title">🎯 Admission Predictor</h1>
          <p className="page-subtitle">ML-powered prediction using 3 algorithms — enter your details below</p>
        </div>
      </div>

      <div className="grid-2" style={{ gap: 20 }}>
        {/* Input Form */}
        <div className="card">
          <div className="card-title mb-16">📋 Your Academic Profile</div>

          <div className="form-grid-2 mb-16">
            <div className="form-group">
              <label className="form-label">10th Percentage (%)</label>
              <input className="form-input" type="number" min="0" max="100" value={form.p10} onChange={e => set('p10', e.target.value)} />
            </div>
            <div className="form-group">
              <label className="form-label">12th Percentage (%)</label>
              <input className="form-input" type="number" min="0" max="100" value={form.p12} onChange={e => set('p12', e.target.value)} />
            </div>
            <div className="form-group">
              <label className="form-label">CGPA (0 – 10)</label>
              <input className="form-input" type="number" step="0.1" min="0" max="10" value={form.cgpa} onChange={e => set('cgpa', e.target.value)} />
            </div>
            <div className="form-group">
              <label className="form-label">Entrance Exam Score</label>
              <input className="form-input" type="number" value={form.entrance} onChange={e => set('entrance', e.target.value)} />
            </div>
            <div className="form-group">
              <label className="form-label">Entrance Exam</label>
              <select className="form-select" value={form.exam} onChange={e => set('exam', e.target.value)}>
                {EXAMS.map(e => <option key={e}>{e}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Category</label>
              <select className="form-select" value={form.category} onChange={e => set('category', e.target.value)}>
                {CATS.map(c => <option key={c}>{c}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Preferred Branch</label>
              <select className="form-select" value={form.branch} onChange={e => set('branch', e.target.value)}>
                {BRANCHES.map(b => <option key={b}>{b}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label className="form-label">Home State</label>
              <select className="form-select" value={form.state} onChange={e => set('state', e.target.value)}>
                {STATES.map(s => <option key={s}>{s}</option>)}
              </select>
            </div>
          </div>

          <div className="form-group mb-16">
            <label className="form-label">Extra-Curricular Activities</label>
            <select className="form-select" value={form.extra} onChange={e => set('extra', e.target.value)}>
              {EXTRAS.map(x => <option key={x}>{x}</option>)}
            </select>
          </div>

          {/* ML Tags */}
          <div className="flex gap-8 mb-16" style={{ flexWrap: 'wrap' }}>
            {ML_MODELS.map(m => (
              <div key={m.key} className="ml-model-tag" style={{ color: m.color, borderColor: `${m.color}40`, background: `${m.color}10`, padding: '5px 12px', borderRadius: 'var(--r-full)', fontSize: '0.72rem', fontWeight: 600, display: 'inline-flex', alignItems: 'center', gap: 6 }}>
                <span style={{ width: 7, height: 7, borderRadius: '50%', background: m.color, display: 'inline-block' }} />
                {m.label}
              </div>
            ))}
          </div>

          <button className="btn btn-primary btn-lg btn-full" onClick={runPrediction} disabled={loading}>
            {loading ? '🔄 Running Models…' : '🚀 Predict Admission Chances'}
          </button>
        </div>

        {/* Results */}
        <div>
          {!result && !loading && (
            <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
              <div style={{ fontSize: 48, marginBottom: 16 }}>🎯</div>
              <h3 style={{ fontFamily: 'var(--font-display)', marginBottom: 8 }}>Ready to Predict</h3>
              <p className="text-muted text-sm">Fill in your details and click "Predict" to get your personalized admission chances.</p>
            </div>
          )}

          {loading && (
            <div className="card" style={{ textAlign: 'center', padding: '48px 24px' }}>
              <div style={{ fontSize: 48, marginBottom: 16, animation: 'spin 1s linear infinite', display: 'inline-block' }}>⚙️</div>
              <style>{`@keyframes spin{from{transform:rotate(0)}to{transform:rotate(360deg)}}`}</style>
              <h3 style={{ fontFamily: 'var(--font-display)', marginBottom: 8 }}>Running ML Models…</h3>
              {ML_MODELS.map((m, i) => (
                <div key={m.key} style={{ display: 'flex', alignItems: 'center', gap: 10, padding: '8px 0', borderBottom: '1px solid var(--border-subtle)' }}>
                  <div style={{ width: 8, height: 8, borderRadius: '50%', background: m.color, animation: `pulse 1s ${i * 0.3}s infinite` }} />
                  <span style={{ fontSize: '0.8rem', color: 'var(--text-secondary)' }}>{m.label}</span>
                  <div style={{ flex: 1, height: 3, background: 'var(--bg-overlay)', borderRadius: 99, overflow: 'hidden' }}>
                    <div style={{ height: '100%', background: m.color, width: '70%', borderRadius: 99, animation: 'loading 0.8s ease-in-out infinite alternate' }} />
                  </div>
                  <style>{`@keyframes loading{from{width:20%}to{width:90%}}`}</style>
                </div>
              ))}
            </div>
          )}

          {result && (
            <>
              {/* Main result */}
              <div className="card mb-16">
                <div className="card-title mb-16">🎯 Prediction Results</div>
                <div className="pred-result-box mb-16">
                  <div className="pred-percentage">{result.overall}%</div>
                  <div className="pred-label">Overall Admission Probability</div>
                  <div className="pred-rank">Predicted Rank: ~{result.rank.toLocaleString('en-IN')}</div>
                </div>

                {/* Per-model */}
                <div className="ml-model-grid">
                  {ML_MODELS.map(m => (
                    <div key={m.key} className="ml-model-card">
                      <div className="ml-model-name">{m.label}</div>
                      <div className="ml-model-score" style={{ color: m.color }}>{result[m.key]}%</div>
                      <div style={{ fontSize: '0.68rem', color: 'var(--text-muted)', marginTop: 6, lineHeight: 1.4 }}>{m.desc}</div>
                    </div>
                  ))}
                </div>
              </div>

              {/* Eligible Colleges */}
              <div className="card">
                <div className="card-title mb-12">🏛️ Eligible Colleges ({eligible.length})</div>
                <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
                  {eligible.length === 0 && <p className="text-muted text-sm">No eligible colleges found. Improve your scores and try again.</p>}
                  {eligible.map(c => (
                    <div key={c.id} className="flex items-center gap-12" style={{ padding: '10px 12px', background: 'var(--bg-elevated)', borderRadius: 'var(--r-md)', border: '1px solid var(--border-subtle)' }}>
                      <div style={{ fontSize: 18 }}>🏛️</div>
                      <div style={{ flex: 1 }}>
                        <div style={{ fontSize: '0.85rem', fontWeight: 700 }}>{c.name}</div>
                        <div className="text-xs text-muted">{c.fees} · {c.placement} avg</div>
                      </div>
                      <span className={`badge ${c.match >= 80 ? 'badge-success' : c.match >= 70 ? 'badge-primary' : 'badge-warn'}`}>{c.match}%</span>
                    </div>
                  ))}
                </div>
              </div>
            </>
          )}
        </div>
      </div>
    </div>
  );
}
